mapper.update:
update chat_message
set status    = 2,
    read_time = now()
where conversation_id = #{conversationId}
  and receiver_id = #{receiverId}
  and id <= #{lastReadMessageId}
  and status < 2

mapper.select:
select id, conversation_id, sender_id, receiver_id, msg_type, content, order_id, goods_id, client_msg_id, status, create_time, deliver_time, read_time from chat_message where conversation_id = #{conversationId}
and id < #{beforeId}
and create_time >= date_sub(now(), interval #{daysAgo} day)
order by id desc limit #{limit}
